# eth_getLogs range limited. Let's check if there's a better approach.
# The real solution: use the Relay currencies list + readContract for balanceOf
# That's what we already do as fallback. Let's verify it actually works.

# Test readContract (eth_call) on Base public RPC for USDC balance
curl -s -X POST "https://mainnet.base.org" \
  -H "Content-Type: application/json" \
  -d '{
    "jsonrpc":"2.0","id":1,"method":"eth_call",
    "params":[{
      "to": "0x833589fcd6edb6e08f4c7c32d4f71b54bda02913",
      "data": "0x70a08231000000000000000000000000d8dA6BF26964aF9D7eEd9e03E53415D37aA96045"
    }, "latest"]
  }' 2>/dev/null

